1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
5	
6	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	const basePremium = (item: any): number => {
14	  if (!isComponent(item) && !(item.type in BASE_PREMIUMS)) {
15	    throw new Error(`Unknown item type: ${item.type}`);
16	  }
17	  return BASE_PREMIUMS[item.type] ?? 0;
18	};
19	
20	const itemSurcharges = (item: any): number => {
21	  const base = basePremium(item);
22	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
23	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
24	  return cursedSurcharge + enchantmentSurcharge;
25	};
26	
27	const totalComponentPremium = (items: any[]): number => {
28	  const components = items.filter(isComponent);
29	  const counts: Record<string, number> = {};
30	  for (const c of components) {
31	    counts[c.type] = (counts[c.type] ?? 0) + 1;
32	  }
33	  let total = 0;
34	  for (const count of Object.values(counts)) {
35	    if (count === 3) {
36	      total += BLOCK_PREMIUM;
37	    } else {
38	      total += count * COMPONENT_PREMIUM;
39	    }
40	  }
41	  return total;
42	};
