44	const calculateQuotePremium = (items: any[], customer: any, isFollowUp: boolean): number => {
45	  const mainItems = items.filter((i: any) => !isComponent(i));
46	  const mainBaseTotal = mainItems.reduce(
47	    (sum: number, item: any) => sum + basePremium(item),
48	    0,
49	  );
50	  const mainSurchargesTotal = mainItems.reduce(
51	    (sum: number, item: any) => sum + itemSurcharges(item),
52	    0,
53	  );
54	  const compTotal = totalComponentPremium(items);
55	  const policyBase = mainBaseTotal + compTotal;
56	  const firstInsurance = policyBase * 0.1;
57	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
58	  const followUpDiscount = isFollowUp ? policyBase * 0.15 : 0;
59	  return Math.ceil(PROCESSING_FEE + mainBaseTotal + mainSurchargesTotal + compTotal + firstInsurance - loyaltyDiscount - followUpDiscount);
60	};
