77	  const insuranceSum = policy.items.reduce(
78	    (sum: number, item: any) => sum + insuranceValue(item), 0
79	  );
80	  const cap = insuranceSum * 2;
81	  let totalPayout = 0;
82	  for (const damage of incident.damages) {
83	    const item = policy.items.find((i: any) => i.type === damage.itemType);
84	    const reimbursement = item && item.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
85	    const payout = reimbursement - DEDUCTIBLE;
86	    totalPayout += payout;
87	  }
88	  return { payout: totalPayout, remainingCap: cap - totalPayout };
89	};
