91	export const processScenario = (scenario: any): any => {
92	  let quoteCount = 0;
93	  const policies: any[] = [];
94	  const results = scenario.steps.map((step: any, index: number) => {
95	    if (step.op === "claim") {
96	      return calculateClaimPayout(policies[step.policy], step.incident);
97	    }
98	    policies[index] = { items: step.items };
99	    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount > 0);
100	    quoteCount++;
101	    return { premium };
102	  });
103	  return { results };
104	};
