const DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;

const insuranceValue = (item: any): number => {
  if (isComponent(item)) return 250;
  return INSURANCE_VALUES[item.type] ?? 0;
};

const reimbursementAmount = (item: any, damageAmount: number): number => {
  if (item && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
  }
  return damageAmount;
};

const calculateClaimPayout = (policy: any, incident: any): { payout: number; remainingCap: number } => {
  const insuranceSum = policy.items.reduce(
    (sum: number, item: any) => sum + insuranceValue(item), 0
  );
  const cap = insuranceSum * 2;
  let totalPayout = 0;
  for (const damage of incident.damages) {
    const item = policy.items.find((i: any) => i.type === damage.itemType);
    const payout = reimbursementAmount(item, damage.amount) - DEDUCTIBLE;
    totalPayout += payout;
  }
  return { payout: totalPayout, remainingCap: cap - totalPayout };
};

